contract StakeDelegationContract {
    mapping(address => uint) public delegation;
    mapping(address => bool) public validators;

    function delegateStake(address validator) external payable {
        require(validators[validator], "Validator not eligible for delegation.");
        require(msg.value > 0, "Stake amount must be greater than zero.");

        delegation[validator] += msg.value;
    }

    function setValidator(address validator, bool active) external {
        // Set eligible validators for delegation
        validators[validator] = active;
    }

    function withdrawStake(address validator) external {
        uint amount = delegation[validator];
        require(amount > 0, "No delegated stake to withdraw.");

        delegation[validator] = 0;
        payable(msg.sender).transfer(amount);
    }
}
